def get_airline(iata: str):
    """Return the airline map for an IATA code (e.g., 'ET')."""
    return AIRLINE_LOGOS.get(iata.upper())

def get_logo_path(iata: str, fmt: str = "svg"):
    """Return the local asset path for an airline logo ('svg' or 'png')."""
    a = get_airline(iata)
    if not a:
        return None
    key = "asset_path_svg" if fmt.lower() == "svg" else "asset_path_png"
    return a.get(key)
